var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"콜록, 콜록……!","JPN":"ゲホッ、ゲホッ……！","ENG":"*Cough* *Cough*","TWN":"咳咳、咳咳……！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"으윽! 갑자기 무슨……. 어디서 가스라도 터진 건가?","JPN":"ううっ！　いきなり……どこかでガスが爆発したのか？","ENG":"Ngh! What was that...? Did a gas explosion happen somewhere?","TWN":"呃！突然發生什麼事了……哪裡瓦斯爆炸了嗎？"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"운이 좋았어. 팔도 다리도 멀쩡해.","JPN":"運がよかった……腕も足もなんともない。","ENG":"I got lucky. All my limbs are fine.","TWN":"運氣還不錯，手臂和腿都還完好。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"잠깐, 아이는!?","JPN":"しまった、子どもは！？","ENG":"Wait, what about the kid?!","TWN":"等等，孩子呢？！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_GIRL","text":{"KOREA":"으으…….","JPN":"うう……","ENG":"Ngh...","TWN":"咳咳……"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"다행이야. 미약하지만, 아직 숨을 쉬고 있어.","JPN":"浅いけどまだ呼吸している。よかった。","ENG":"Thank goodness. It's weak, but she's still breathing.","TWN":"太好了。雖然很微弱，但好歹還有呼吸。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"하지만 공기 호흡기가 망가졌어.","JPN":"でも呼吸器が壊れてしまったな。","ENG":"But my oxygen tank is broken.","TWN":"但我的空氣呼吸器壞掉了。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"이대로는 얼마 못 버틸 거야. 빨리 여기서 나가야…… ","JPN":"このままだと長く持たない。早くここから出ないと…… ","ENG":"We won't be able to last long. We need to get out of here...","TWN":"這樣下堅持不了太久。我得趕緊離開這裡……"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"어?","JPN":"え？","ENG":"Huh?","TWN":"呃？"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAP","text":{"KOREA":"끄으윽……!","JPN":"ぐうぅ……！","ENG":"Errrgh...!","TWN":"咳呃……！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"대, 대장님!? 정신 차리십시오!!","JPN":"た、隊長！？　しっかりしてください！！","ENG":"C-Captain?! You okay?!","TWN":"隊、隊長？！你醒醒！！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAP","text":{"KOREA":"꼴통……?","JPN":"お前か……？","ENG":"Knucklehead...?","TWN":"小丫頭……？"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAP","text":{"KOREA":"아이는……? 구조자는 어떻게 됐어……?","JPN":"子どもは……？　救助者は、どうなった……？","ENG":"The child.. What happened to her...?","TWN":"孩子呢……？求救者怎麼樣了……？"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"살아있습니다!","JPN":"生きています！","ENG":"She's alive!","TWN":"她還活著！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그, 그보다……! 무너진 건물 잔해가 대장님의 하반신을 짓누르고 있습니다!","JPN":"そ、それより……！　隊長の下半身が瓦礫に埋もれています！","ENG":"B-besides that...! The rubble from the collapsed building crushed your lower body!","TWN":"不、不過……！隊長，你下半身被壓在了殘骸下面！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"피가, 피가 많이 난다고요!!","JPN":"血が……出血がひどい……！！","ENG":"Th-there's a lot of blood!!","TWN":"血，你流了好多血！！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAP","text":{"KOREA":"그러냐……? 이상하다. 왜 하나도 안 아프지……?","JPN":"そうか……？　おかしいな、全然痛くねえ……","ENG":"Is that so...? That's odd. Why don't I feel any pain...?","TWN":"是嗎……？奇怪，我為什麼一點都不覺得痛……？"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"지금 꺼내드릴 테니까, 더는 아무 말도 하지 마십시오!","JPN":"今助けますから、何も喋らないで！！","ENG":"I'll get you out now, so stop talking!","TWN":"我現在就救你出來，你別再說話了！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"으으윽!! 제발!! 제발 움직여……!!","JPN":"うううっ！！　動け！！　お願いだから、動いてくれ……！！","ENG":"Ngh!! C'mon!! MOOOVE...!!","TWN":"呃啊！！加把勁！！快抬起來了……！！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAP","text":{"KOREA":"끄으윽!","JPN":"ぐうぅ……！","ENG":"ERRRGH!","TWN":"咳呃!"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"조금만…… 조금만 더 버티는 겁니다……!!","JPN":"もう少し……もう少し耐えてください……！！","ENG":"Just hang in there... a little longer...!!","TWN":"再……再堅持一下……！！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"으윽!! 제가…… 제가 반드시……!!","JPN":"ううっ！！　アタシが……アタシが必ず……！！","ENG":"Argh!! I'll... get you...!","TWN":"呃啊！！我……我一定……！！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"으으!! 으아아아아아아아아아아아……!!","JPN":"うう……うああああああああ……！！","ENG":"Agh!! AAAAARGH...!!","TWN":"呃呃！！啊啊啊……！！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"하아, 하아, 하아……!!","JPN":"はあ、はあ、はあ……！！","ENG":"*Huff* *Huff* *Huff*","TWN":"哈啊，哈啊，哈啊……！！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"됐다! 잔해를 치웠어!","JPN":"よし、やった！　瓦礫をどかせた！","ENG":"I did it! I cleared the rubble!","TWN":"好了！清理完了！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};